/**
 * Security Middleware
 * 
 * HTTP security headers, rate limiting, and request logging
 */

import { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';
import rateLimit from 'express-rate-limit';

// ============================================
// HTTP SECURITY HEADERS (Helmet)
// ============================================

export const securityHeaders = helmet({
    // Content Security Policy
    contentSecurityPolicy: {
        directives: {
            defaultSrc: ["'self'"],
            scriptSrc: ["'self'", "'unsafe-inline'", "'unsafe-eval'", "https://js.clerk.dev", "https://challenges.cloudflare.com"],
            styleSrc: ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com"],
            fontSrc: ["'self'", "https://fonts.gstatic.com"],
            imgSrc: ["'self'", "data:", "blob:", "https:"],
            connectSrc: ["'self'", "https://*.clerk.dev", "https://api.razorpay.com", "wss:", "ws:"],
            frameSrc: ["https://*.clerk.dev", "https://api.razorpay.com"],
            objectSrc: ["'none'"],
            upgradeInsecureRequests: []
        }
    },
    // Prevent clickjacking
    frameguard: { action: 'deny' },
    // Prevent MIME type sniffing
    noSniff: true,
    // Force HTTPS (disable in development)
    hsts: process.env['NODE_ENV'] === 'production' ? {
        maxAge: 31536000, // 1 year
        includeSubDomains: true,
        preload: true
    } : false,
    // XSS filter
    xssFilter: true,
    // Hide X-Powered-By header
    hidePoweredBy: true,
    // Prevent IE from executing downloads
    ieNoOpen: true,
    // DNS prefetch control
    dnsPrefetchControl: { allow: false }
});

// ============================================
// RATE LIMITING
// ============================================

// General API rate limit: 100 requests per minute
export const generalRateLimit = rateLimit({
    windowMs: 60 * 1000, // 1 minute
    max: 100,
    message: {
        success: false,
        error: 'Too many requests, please try again later.',
        retryAfter: 60
    },
    standardHeaders: true,
    legacyHeaders: false,
    skip: (req) => req.path === '/health'
});

// Analysis API rate limit: 10 requests per minute
export const analysisRateLimit = rateLimit({
    windowMs: 60 * 1000,
    max: 10,
    message: {
        success: false,
        error: 'Analysis rate limit exceeded. Please wait before running more analyses.',
        retryAfter: 60
    },
    standardHeaders: true,
    legacyHeaders: false
});

// Billing API rate limit: 5 requests per minute (prevent abuse)
export const billingRateLimit = rateLimit({
    windowMs: 60 * 1000,
    max: 5,
    message: {
        success: false,
        error: 'Billing rate limit exceeded. Please try again later.',
        retryAfter: 60
    },
    standardHeaders: true,
    legacyHeaders: false
});

// Auth endpoints rate limit: 5 requests per minute (prevent brute force)
export const authRateLimit = rateLimit({
    windowMs: 60 * 1000,
    max: 5,
    message: {
        success: false,
        error: 'Too many auth attempts. Please try again later.',
        retryAfter: 60
    },
    standardHeaders: true,
    legacyHeaders: false
});

// ============================================
// REQUEST LOGGING
// ============================================

export const requestLogger = (req: Request, _res: Response, next: NextFunction) => {
    const timestamp = new Date().toISOString();
    const method = req.method;
    const url = req.originalUrl;
    const ip = req.ip || req.connection.remoteAddress || 'unknown';
    const userAgent = req.get('user-agent') || 'unknown';

    // Log request (in production, send to logging service)
    console.log(`[${timestamp}] ${method} ${url} - IP: ${ip} - UA: ${userAgent.slice(0, 50)}`);

    next();
};

// ============================================
// ERROR HANDLER (Hide stack traces in production)
// ============================================

export const secureErrorHandler = (
    err: Error,
    _req: Request,
    res: Response,
    _next: NextFunction
) => {
    console.error('[ERROR]', err.message);

    // Don't expose internal errors to client
    const isDev = process.env['NODE_ENV'] !== 'production';

    res.status(500).json({
        success: false,
        error: isDev ? err.message : 'Internal server error',
        ...(isDev && { stack: err.stack })
    });
};

// ============================================
// EXPORTS
// ============================================

export default {
    securityHeaders,
    generalRateLimit,
    analysisRateLimit,
    billingRateLimit,
    authRateLimit,
    requestLogger,
    secureErrorHandler
};
